"""
mkt-christ commentary — Leviticus 26–27 (80 verses)
Ch26: The blessing and curse covenant (Holiness Code conclusion) — Christ bore the curse
      (Gal 3:13), fulfilled the covenant conditions, and secures the restoration promise
Ch27: Vows and dedications — firstborn, redemption values, the Jubilee backdrop,
      Christ as the firstborn of all creation and the ransomer of the devoted
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LEVITICUS_CHRIST = {
  "26": {
    "1": "<p>An allusion: 'You shall not make idols for yourselves or erect an image or pillar.' The idol prohibition opens the covenant's blessing-and-curse section — the first commandment grounds the whole. Christ is the true image: 'He is the image (<em>eikon</em>) of the invisible God' (Col 1:15). The prohibition against crafted images is the negative side of which Christ's incarnation is the positive: the uncraftable, unimaginable God has given humanity his own true image in the Son.</p>",
    "2": "<p>An allusion: 'You shall keep my Sabbaths and reverence my sanctuary: I am YHWH.' Christ is Lord of the Sabbath (Mark 2:28; Matt 12:8) — not merely a keeper of the Sabbath command but its source and fulfillment. 'The Sabbath was made for man, not man for the Sabbath' — Christ reinterprets the Sabbath's purpose as his own to define. His resurrection on the first day reshapes the Sabbath into the Lord's Day, the new-creation Sabbath.</p>",
    "3": "<p>An allusion: 'If you walk in my statutes and observe my commandments and do them...' — the conditional clause that opens the blessing section. Christ is the only one who fully met this condition. His perfect obedience (Phil 2:8; Heb 5:8-9) is the ground on which the blessings of vv.4-13 flow to his people. The conditionality of Leviticus 26 is not abolished but fulfilled: Christ fulfills the condition so that those in him receive the blessings unconditionally.</p>",
    "4": "<p>An allusion: the rain in its season and the harvest blessing follow covenant faithfulness. Christ's perfect obedience to the Father brings the harvest of the redeemed: 'Unless a grain of wheat falls into the earth and dies, it remains alone; but if it dies, it bears much fruit' (John 12:24). The agricultural harvest of Lev 26:4 is the natural type; the harvest of souls gathered by Christ's death and resurrection is the spiritual fulfillment.</p>",
    "5": "<p>An allusion: threshing reaching to the grape harvest, grape harvest reaching to the sowing — unending abundance following obedience. Amos 9:13 echoes this vision: 'The plowman shall overtake the reaper.' Christ's kingdom is described in harvest terms throughout the Gospels (Matt 9:37-38; 13:23; John 4:35-36). The abundance of Lev 26:5 is the type of the kingdom harvest that knows no end.</p>",
    "6": "<p>A direct type: 'I will give peace in the land... and the sword shall not go through your land.' Christ is 'the Prince of Peace' (Isa 9:6) who 'made peace by the blood of his cross' (Col 1:20). 'He himself is our peace, who has made us both one and has broken down in his flesh the dividing wall of hostility' (Eph 2:14). The peace of the blessed land in Lev 26:6 — security from enemies, harmony in the community — is the type of the comprehensive shalom Christ brings.</p>",
    "7": "<p>An allusion: five chasing a hundred, the miraculous multiplication of power in victory. Christ's disciples went out as 'sheep among wolves' (Matt 10:16) — the ratio was impossibly against them — yet the early church's expansion shows precisely this pattern: small numbers producing disproportionate impact under the Spirit's power (Acts 2:41; 4:4).</p>",
    "8": "<p>An allusion: 'Five of you shall chase a hundred, and a hundred of you shall chase ten thousand, and your enemies shall fall before you by the sword.' The disproportionate victory covenant. Christ promises the same to his church: 'I will build my church, and the gates of hell shall not prevail against it' (Matt 16:18). The gates of Hades — the defensive fortifications of death itself — cannot withstand the advance of Christ's people.</p>",
    "9": "<p>An allusion: 'I will turn to you and make you fruitful and multiply you and confirm my covenant with you.' The Abrahamic fruitfulness promise renewed through covenant obedience. Christ as the seed of Abraham through whom all nations are blessed (Gal 3:16); the church as the Abrahamic family multiplied beyond reckoning (Gal 3:29). The new covenant 'confirms' (establishes firmly, Heb 9:15-17) what the old covenant anticipated.</p>",
    "10": "<p>An allusion: 'You shall eat old store long kept, and you shall clear out the old to make way for the new.' The old harvest cleared to make room for the new. The new covenant making way by superseding — not destroying — the old: 'What is becoming obsolete and growing old is ready to vanish away' (Heb 8:13). Christ does not patch the old garment; he brings the new wine that requires new wineskins (Matt 9:16-17).</p>",
    "11": "<p>A direct type: 'I will make my dwelling (<em>mishkan</em>) among you, and my soul shall not abhor you.' The divine dwelling among Israel is the tabernacle promise. John 1:14 fulfills it: 'The Word became flesh and <em>tabernacled</em> (<em>eskēnōsen</em>) among us.' The same root (<em>shakan/mishkan</em>) underlies both the tabernacle and John's incarnation description. In Christ the <em>mishkan</em> promise becomes literal: God's presence is not in a tent but in a human body.</p>",
    "12": "<p>A direct fulfillment: 'And I will walk among you and will be your God, and you shall be my people.' The foundational covenant formula. Paul quotes this verse in 2 Corinthians 6:16 as the basis for the church's identity as the temple of the living God: 'For we are the temple of the living God; as God said: I will make my dwelling among them and walk among them.' The new covenant community is the fulfillment of the walking-among-you promise — YHWH tabernacling in his Spirit-indwelt people.</p>",
    "13": "<p>An allusion: 'I am YHWH your God, who brought you out of the land of Egypt, that you should not be their slaves. And I have broken the bars of your yoke and made you walk erect.' Christ's easy yoke replaces the crushing yoke: 'Come to me, all who labor and are heavy laden, and I will give you rest. Take my yoke upon you and learn from me, for I am gentle and lowly in heart, and you will find rest for your souls. For my yoke is easy, and my burden is light' (Matt 11:28-30). He broke the bars of the law's condemning power (Gal 3:13; Col 2:14) to make the redeemed walk erect in dignity.</p>",
    "14": "<p>An allusion: 'But if you will not listen to me and will not do all these commandments...' — the curse section begins. This is the legal framework within which Christ's atoning work operates: the curse is real; the covenant threatened real consequences. Galatians 3:10: 'All who rely on works of the law are under a curse, for it is written: Cursed is everyone who does not abide by all things written in the Book of the Law and do them.' The 'if' of Lev 26:14 becomes the 'since' of human reality; the 'but' of grace enters in Christ.</p>",
    "15": "<p>An allusion: rejecting YHWH's statutes and breaking the covenant — this is the condition that makes the curse operative. The ultimate rejection of the covenant was the rejection of Christ himself (John 1:11). Yet in a stunning reversal, the one rejected became the bearer of the rejection's consequences: 'He was despised and rejected by men' (Isa 53:3) precisely in order that those who rejected him might be forgiven.</p>",
    "16": "<p>An allusion: the first curse tier — diseases, wasting, fever, eyes consumed, life drained. Christ took on all the infirmities of the curse: 'He took our illnesses and bore our diseases' (Matt 8:17, quoting Isa 53:4). The healing ministry of Jesus was not incidental to his mission but its enacted sign: he absorbed the curse's symptoms in his own body and began reversing them in others, previewing the total reversal of the curse at the resurrection.</p>",
    "17": "<p>An allusion: 'I will set my face against you, and you shall be struck down before your enemies.' The curse of divine opposition — YHWH's face turned against rather than toward. Christ on the cross experienced the ultimate form of this: 'My God, my God, why have you forsaken me?' (Matt 27:46). The God-abandonment of Psalm 22 is the total form of what Lev 26:17 threatens: the covenant God turning his face away.</p>",
    "18": "<p>An allusion: 'And if in spite of this you will not listen to me, then I will discipline you again sevenfold for your sins.' The sevenfold escalation of judgment. Christ bore not a minimal judgment but a complete one — the full weight of divine wrath against sin (Rom 3:25-26; 1 John 2:2). The 'sevenfold' completeness of the curse in Lev 26:18, 21, 24, 28 corresponds to the completeness of atonement Christ made: 'It is finished' (John 19:30).</p>",
    "19": "<p>An allusion: 'I will break the pride of your power, and I will make your heavens like iron and your earth like bronze.' The arrogance that produces covenant failure is crushed. Christ, by contrast, 'humbled himself by becoming obedient to the point of death, even death on a cross' (Phil 2:8). His was the opposite of the pride that draws the curse — his self-emptying obedience is the ground of his people's exaltation (Phil 2:9-11).</p>",
    "20": "<p>An allusion: 'And your strength shall be spent in vain, for your land shall not yield its increase, and the trees of the land shall not yield their fruit.' The futility curse — labor that produces nothing. Paul describes the creation's futility in similar terms (Rom 8:20-21) and the new creation's liberation from it. Christ's resurrection is the firstfruits of the liberation from futility: 'Your labor in the Lord is not in vain' (1 Cor 15:58).</p>",
    "21": "<p>An allusion: the second curse tier — the sevenfold plague escalation for ongoing disobedience. The graduated nature of the curse reflects the graduated nature of divine patience: YHWH gives opportunity after opportunity to repent before the full curse falls. Christ's ministry echoed this: 'O Jerusalem, Jerusalem, the city that kills the prophets... How often would I have gathered your children together as a hen gathers her brood under her wings, and you were not willing!' (Matt 23:37).</p>",
    "22": "<p>An allusion: 'I will let loose the wild beasts against you, which shall bereave you of your children and destroy your livestock and make you few in number.' The created order turning against the covenant people. In contrast, when Christ faced his wilderness temptation he was 'with the wild animals, and the angels were ministering to him' (Mark 1:13) — a deliberate echo of Eden's lost harmony, restored in the new Adam. Where covenant failure unleashes wild beasts, Christ's presence restores the peaceable kingdom (Isa 11:6-9).</p>",
    "23": "<p>An allusion: 'And if by this discipline you are not turned to me but walk contrary to me...' — the refusal to repent even under judgment. The hardness of heart that refuses chastening was the spiritual condition of the generation that rejected Christ (John 12:40; Matt 13:15). The curse section of Lev 26 traces the progressive hardening that ultimately required not more chastening but a wholly new redemptive act.</p>",
    "24": "<p>An allusion: 'Then I also will walk contrary to you, and I myself will strike you sevenfold for your sins.' The divine-contrary posture mirrors the human-contrary posture — the relationship has broken down completely. Christ came precisely at the point of this total relational breakdown: 'But when the fullness of time had come, God sent forth his Son, born of woman, born under the law, to redeem those who were under the law' (Gal 4:4-5).</p>",
    "25": "<p>An allusion: 'I will bring a sword upon you, that shall execute vengeance for the covenant.' The sword of covenant enforcement — the judgment side of the legal covenant. Zechariah 13:7: 'Awake, O sword, against my shepherd, against the man who stands next to me.' Christ quoted this verse at Gethsemane (Matt 26:31): the covenant sword fell on the shepherd rather than the sheep. The covenant's punishing sword was borne by the mediator.</p>",
    "26": "<p>A direct type: 'When I break your supply of bread, ten women shall bake your bread in a single oven and shall dole out your bread again by weight, and you shall eat and not be satisfied.' The curse of insufficient bread is the negative image of Christ's miraculous feeding: 'I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst' (John 6:35). Where the curse produces scarcity and dissatisfaction, Christ produces superabundance: 'They all ate and were satisfied, and they took up twelve baskets full of broken pieces' (Matt 14:20).</p>",
    "27": "<p>An allusion: continued disobedience despite the staff of bread being broken — still not turning. The stubbornness of the human heart under judgment illustrates why the incarnation was necessary: no amount of external pressure produces the internal transformation only Christ can accomplish. 'I will give you a new heart and a new spirit I will put within you. And I will remove the heart of stone from your flesh and give you a heart of flesh' (Ezek 36:26).</p>",
    "28": "<p>An allusion: 'I will walk contrary to you in fury, and I myself will discipline you sevenfold for your sins.' The divine fury — the wrath of the covenant God against covenant-breaking. This is the wrath that Christ absorbed: 'God put him forward as a propitiation by his blood' (Rom 3:25). The fury of Lev 26:28 is the reality that makes propitiation necessary; Christ's blood is the answer the curse section anticipates.</p>",
    "29": "<p>An allusion: the extremity of the curse — cannibalism of sons and daughters, the ultimate sign of covenant breakdown. This was literally fulfilled in the sieges of Jerusalem (2 Kgs 6:28-29; Lam 4:10) as Jesus foresaw the same for 70 CE (Luke 21:20-24). Christ wept over Jerusalem (Luke 19:41-44) knowing the curse's full weight would fall there. The depths of sin's consequences that Lev 26:29 describes are the depths into which Christ descended to redeem.</p>",
    "30": "<p>An allusion: 'I will destroy your high places and cut down your incense altars and cast your dead bodies upon the dead bodies of your idols, and my soul will abhor you.' The destruction of false worship. Christ triumphed over all false spiritual powers: 'He disarmed the rulers and authorities and put them to open shame, by triumphing over them in him' (Col 2:15). The cross dismantled the system of false mediation between humanity and God — the high places made redundant by the true high priest.</p>",
    "31": "<p>A direct type: 'And I will lay your cities waste and will make your sanctuaries desolate.' Christ predicted the literal fulfillment of this for the temple: 'There will not be left here one stone upon another that will not be thrown down' (Matt 24:2; fulfilled 70 CE). But he also declared himself the replacement sanctuary: 'Destroy this temple, and in three days I will raise it up... he was speaking about the temple of his body' (John 2:19-21). The desolated sanctuary is the shadow; Christ as the eternal temple is the fulfillment.</p>",
    "32": "<p>An allusion: 'And I myself will devastate the land, so that your enemies who settle in it shall be appalled by it.' The exile — Israel's land under desolation. The exile's desolation created the longing for the one who would restore: the prophetic hope generated in the exile (Isaiah, Jeremiah, Ezekiel) is the most Christologically rich period of the OT. The desolation of Lev 26:32 is what made Isa 40:1-2's 'Comfort, comfort my people' so urgent.</p>",
    "33": "<p>An allusion: 'And I will scatter you among the nations, and I will unsheathe the sword after you, and your land shall be a desolation, and your cities shall be a waste.' The Diaspora — Israel scattered. Paul interprets the Diaspora as part of YHWH's plan to bring the gospel to the nations: 'through their trespass salvation has come to the Gentiles' (Rom 11:11). The scattering becomes, paradoxically, the seed-spreading of YHWH's purposes.</p>",
    "34": "<p>An allusion: 'Then the land shall enjoy its Sabbaths as long as it lies desolate, while you are in your enemies' land; then the land shall rest, and enjoy its Sabbaths.' The enforced Sabbath rest during exile. Hebrews 4:1-11 develops the Sabbath-rest theology: 'There remains a Sabbath rest for the people of God' — the rest that was not fully achieved in the land-promise, the Canaan-rest pointing beyond itself to the rest in Christ. The land's exile-Sabbath anticipates the eternal rest.</p>",
    "35": "<p>An allusion: the land rests in exile, making up for the Sabbath years Israel did not observe. Christ's final rest — 'It is finished' (John 19:30) — is the ultimate Sabbath declaration: the work of redemption is complete, the debt is paid, the rest is secured. Hebrews 4:10: 'Whoever has entered God's rest has also rested from his works as God did from his.'</p>",
    "36": "<p>An allusion: 'As for those of you who are left, I will send faintness into their hearts in the lands of their enemies. The sound of a driven leaf shall put them to flight, and they shall flee as one flees from the sword.' The spiritual desolation of the scattered people — fear, disorientation, loss of identity. Christ came to gather the scattered: 'He gathers the outcasts of Israel' (Ps 147:2); 'I will seek the lost, and I will bring back the strayed' (Ezek 34:16). The Great Shepherd comes for the frightened, faint-hearted exiles.</p>",
    "37": "<p>An allusion: 'They shall stumble over one another, as if to escape a sword, though none pursues.' The disarray of the cursed community — stumbling without even a real threat. Christ is the one who gathers the stumbling into a community that walks together: 'I am the light of the world. Whoever follows me will not walk in darkness, but will have the light of life' (John 8:12). The stumbling in darkness of Lev 26:37 contrasts with the sure-footed walking in light that Christ provides.</p>",
    "38": "<p>An allusion: 'And you shall perish among the nations, and the land of your enemies shall eat you up.' The threat of permanent assimilation and loss. YHWH's preservation of a remnant through exile was against all odds — precisely what made the return and eventual Messiah-coming possible. Christ came as the fulfillment of the preserved remnant: 'I did not come to abolish the Law or the Prophets but to fulfill them' (Matt 5:17) — the remnant-bearer of all that the exile threatened to destroy.</p>",
    "39": "<p>An allusion: 'And those of you who are left shall rot away in your enemies' lands because of their iniquity, and also because of the iniquities of their fathers they shall rot away like them.' The inherited iniquity — the sins of fathers transmitted to children. Christ broke the cycle of inherited guilt: 'God made him who had no sin to be sin for us, so that in him we might become the righteousness of God' (2 Cor 5:21). The generational rot ends where the one without inherited iniquity absorbs what humanity accumulated.</p>",
    "40": "<p>An allusion: 'But if they confess their iniquity and the iniquity of their fathers in their treachery... then I will remember my covenant.' The turning point — confession as the gateway to covenant restoration. 'If we confess our sins, he is faithful and just to forgive us our sins and to cleanse us from all unrighteousness' (1 John 1:9). The restoration formula of Lev 26:40 is the shadow of the new covenant's forgiveness, grounded not in Israel's confession per se but in Christ's atoning work that makes confession efficacious.</p>",
    "41": "<p>A direct type: 'And walk contrary to me, so that I walked contrary to them and brought them into the land of their enemies — if then their uncircumcised heart is humbled...' The uncircumcised heart is the problem requiring not just external reform but internal transformation. Paul: 'No one is a Jew who is merely one outwardly, nor is circumcision outward and physical. But a Jew is one inwardly, and circumcision is a matter of the heart, by the Spirit, not by the letter' (Rom 2:28-29). Christ gives the circumcision of the heart (Col 2:11) that the covenant always required but could not itself produce.</p>",
    "42": "<p>A direct fulfillment: 'Then I will remember my covenant with Jacob, and I will remember my covenant with Isaac and my covenant with Abraham, and I will remember the land.' The Abrahamic covenant as the bedrock beneath the Sinai structure. Galatians 3:16: 'Now the promises were made to Abraham and to his offspring. It does not say, And to offsprings, referring to many, but to one, And to your offspring, who is Christ.' Christ is the specific seed through whom all three patriarchal covenant strands — Abraham, Isaac, Jacob — are fulfilled.</p>",
    "43": "<p>An allusion: the land enjoys its Sabbath in desolation because Israel did not observe the Sabbath years. Even in the judgment, the creation structure persists — YHWH's order cannot finally be violated without consequence. The Jubilee and Sabbath-year system that created this dynamic is what Paul has in mind when he speaks of the law as a custodian/guardian (Gal 3:24-25): the covenant's legal structures held things in place until the fullness of time when Christ came to fulfill them.</p>",
    "44": "<p>A direct fulfillment: 'Yet for all that, when they are in the land of their enemies, I will not spurn them, neither will I abhor them so as to destroy them utterly and break my covenant with them, for I am YHWH their God.' The unconditional preservation promise embedded within the curses. Paul quotes the prophetic expression of this in Romans 11:26-29: 'All Israel will be saved... As regards election, they are beloved for the sake of their forefathers. For the gifts and calling of God are irrevocable.' YHWH's 'not destroy them utterly' of Lev 26:44 is the root of Paul's 'gifts and calling are irrevocable.'</p>",
    "45": "<p>A direct fulfillment: 'But I will for their sake remember the covenant with their forefathers, whom I brought out of the land of Egypt in the sight of the nations, that I might be their God: I am YHWH.' Hebrews 8:6: Christ 'is the mediator of a better covenant, which is enacted on better promises.' The covenant YHWH promised to remember in Lev 26:45 is ultimately the new covenant mediated by Christ — built on the better promises of Jeremiah 31:31-34, grounded in the better sacrifice of the Son. The 'I will remember' of Lev 26:45 is confirmed in Christ's blood: 'This cup is the new covenant in my blood' (1 Cor 11:25).</p>",
    "46": "<p>A direct type: 'These are the statutes and rules and laws that YHWH made between himself and the people of Israel through Moses on Mount Sinai.' The closing formula of the Holiness Code and the body of Leviticus. Christ: 'Do not think that I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfill them' (Matt 5:17). Every statute of the Holiness Code — the sacrifice regulations, the purity laws, the festival calendar, the blessings and curses — is fulfilled in Christ. He is the end (<em>telos</em>, goal/completion) of the law (Rom 10:4).</p>"
  },
  "27": {
    "1": "<p>An allusion: 'YHWH spoke to Moses, saying...' — the final section of Leviticus opens with the same divine speech formula as every other section. Christ is the greater mediator: 'Long ago, at many times and in many ways, God spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son' (Heb 1:1-2). The law given through Moses is the penultimate word; Christ is the ultimate and definitive Word of God.</p>",
    "2": "<p>An allusion: persons dedicated by a special vow to YHWH. The complete self-dedication of Jesus to the Father's will is the fulfillment of every human vow of dedication: 'My food is to do the will of him who sent me and to accomplish his work' (John 4:34). 'I have come down from heaven, not to do my own will but the will of him who sent me' (John 6:38). His entire earthly life was a vow of dedication to the Father fulfilled without defection.</p>",
    "3": "<p>An allusion: the valuation of a male person between 20-60 years at 50 shekels of silver. The temple's system of monetary valuation for dedicated persons points toward the ultimate valuation. Thirty pieces of silver — the price for which Judas sold Jesus (Matt 26:15) — is the slave's legal price (Exod 21:32) and the price Zechariah received as wages (Zech 11:12-13). The one who was without price was priced by human assessors. Matthew interprets this as fulfillment: 'They took the thirty pieces of silver, the price of him on whom a price had been set' (Matt 27:9).</p>",
    "4": "<p>An allusion: the valuation of a woman 20-60 at 30 shekels. The graduated valuation system reflects the practical economics of temple service (men performed more labor-intensive tasks) without assigning moral worth. In Christ all are redeemed at the same price — his own blood: 'You were bought with a price' (1 Cor 6:20; 7:23). The costly, uniform price of redemption overrides the graduated valuations of the dedication system.</p>",
    "5": "<p>An allusion: the valuations for persons 5-20 years (male 20, female 10 shekels). The age-graduated system acknowledges different capacities for service. Christ receives all ages: 'Let the children come to me, and do not hinder them, for to such belongs the kingdom of heaven' (Matt 19:14). His redemption is not conditioned on capacity or age — all are equally valuable to the one who gave everything.</p>",
    "6": "<p>An allusion: persons 1 month to 5 years — even infants have a valuation in the dedication system. The very young are not outside the covenant's scope. Christ's own dedication to YHWH occurred at 40 days (Luke 2:22-24) — as an infant, he was brought to the temple under the system of Lev 12 and 27. The first temple presentation of the one who would replace the temple is embedded in this dedication law.</p>",
    "7": "<p>An allusion: persons 60 and above (male 15, female 10 shekels). The elderly receive a lower valuation in the labor-capacity system, but Christ honors the elderly: 'Honor your father and mother' (Matt 15:4). Simeon and Anna, both elderly, were the ones who recognized the infant Jesus in the temple (Luke 2:25-38) — the aged witnesses to the one who transcends the value-hierarchy of the dedication law.</p>",
    "8": "<p>An allusion: 'But if someone is too poor to pay the valuation, then he shall be presented before the priest, and the priest shall value him; the priest shall value him according to what the vower can afford.' The graduated mercy of the system — no one is excluded from dedication by poverty. Christ's redemption is available to all regardless of economic status: 'The Spirit of the Lord is upon me, because he has anointed me to proclaim good news to the poor' (Luke 4:18). 'Come, everyone who thirsts, come to the waters; and he who has no money, come' (Isa 55:1).</p>",
    "9": "<p>An allusion: a dedicated animal 'shall be holy to YHWH' — it cannot be exchanged or substituted. Once given to YHWH, the animal is in a category of its own. Christ's sacrifice was a once-for-all event that cannot be replicated or exchanged: 'Nor was it to offer himself repeatedly, as the high priest enters the holy places every year with blood not his own, for then he would have had to suffer repeatedly since the foundation of the world. But as it is, he has appeared once for all at the end of the ages to put away sin by the sacrifice of himself' (Heb 9:25-26).</p>",
    "10": "<p>An allusion: 'He shall not exchange it or make a substitute for it, good for bad or bad for good; and if he does in fact substitute one animal for another, both it and the substitute shall be holy.' The non-exchangeability of the dedicated animal. Christ's sacrifice admits no substitute: there is no other name under heaven given among men by which we must be saved (Acts 4:12). The uniqueness and non-substitutability of the Levitical dedication points to the unrepeatable uniqueness of the cross.</p>",
    "11": "<p>An allusion: an unclean animal that cannot be offered may be brought before the priest for valuation and redemption. The system provides for the redemption of what cannot directly serve as an offering. Christ redeems what is 'unclean' — what cannot by itself approach YHWH: 'While we were still sinners, Christ died for us' (Rom 5:8). He does not require his people to be clean before he redeems them; he redeems the unclean.</p>",
    "12": "<p>An allusion: the priest values the unclean animal 'whether good or bad; as the priest values it, so it shall be.' The priestly assessment determines the redemption price. Christ as the great High Priest who both assesses and pays the redemption price himself — the unique situation where the priest is also the payment (Heb 9:11-14).</p>",
    "13": "<p>An allusion: if the owner wishes to redeem the dedicated unclean animal, he adds a fifth to the valuation. The 20% surcharge recurs throughout Leviticus for inadvertent violations and personal redemptions (Lev 5:16; 6:5; 22:14; 27:15, 19, 31). The surcharge principle acknowledges that removing something from the holy sphere carries a cost beyond the mere assessed value. Christ's redemption cost not a surcharge but everything: 'You were bought with a price' — the price being not silver and gold but 'the precious blood of Christ' (1 Pet 1:18-19).</p>",
    "14": "<p>An allusion: a house dedicated to YHWH is assessed by the priest. The household sanctuary dimension of the dedication law. Christ as the one who makes every home a potential temple: 'If anyone loves me, he will keep my word, and my Father will love him, and we will come to him and make our home with him' (John 14:23). The divine presence that the dedicated house pointed toward comes in the new covenant to dwell in every believer's heart.</p>",
    "15": "<p>An allusion: the owner who redeems his dedicated house adds a fifth. The redemption cost more than the original. This anticipates what became true in the incarnation: the cost of reclaiming what was lost was higher than the original gift. Creation was given freely; redemption cost the Son's blood. Paul: 'He who did not spare his own Son but gave him up for us all, how will he not also with him graciously give us all things?' (Rom 8:32).</p>",
    "16": "<p>An allusion: the dedicated field's valuation is based on the crop yield and the remaining years until Jubilee. The Jubilee year is the theological backdrop for this whole section — the 50-year cycle when debts were cancelled and lands returned to original owners. Christ inaugurated the true Jubilee: 'The Spirit of the Lord is upon me, because he has anointed me to proclaim good news to the poor... to proclaim the year of the Lord's favor' (Luke 4:18-19, citing Isa 61:1-2). The 'year of the Lord's favor' is the Jubilee vocabulary applied to the Messianic age.</p>",
    "17": "<p>An allusion: a field dedicated from the Jubilee year gets the full valuation. The proximity to Jubilee determines the value — the closer to the year of release, the higher the value. In Christ the Jubilee has arrived permanently: the release is not 50 years hence but already present. 'Now is the acceptable time; behold, now is the day of salvation' (2 Cor 6:2). The Levitical field-valuation tied to temporal Jubilee points to the timeless Jubilee of redemption.</p>",
    "18": "<p>An allusion: a field dedicated after the Jubilee year is valued proportionally to the remaining years. The diminishing value as Jubilee recedes mirrors the way the old covenant system was always running down toward its fulfillment-point. Each year further from the last Jubilee meant more years of servitude remaining. Christ's coming was the final Jubilee that need never run down: his release is permanent.</p>",
    "19": "<p>An allusion: the owner who redeems his dedicated field adds a fifth to the valuation. The redemption surcharge applies here as in the house (v.15). The costliness of redemption is a consistent theme: bringing something back from the divine sphere into ordinary use always costs more than it was originally worth. This anticipates the costliness of Christ's work — redemption from YHWH's ownership back to human possession required the supreme payment.</p>",
    "20": "<p>An allusion: if the field is sold to another person before being redeemed, it cannot be redeemed. The point of no return in the human system. Christ's redemption knows no such limit: 'And they are justified by his grace as a gift, through the redemption that is in Christ Jesus' (Rom 3:24). No human debt-situation is so hopelessly transferred that Christ cannot redeem — he has already paid the price for all who will come to him.</p>",
    "21": "<p>An allusion: a field that goes unredeemed at Jubilee becomes <em>cherem</em> (devoted, irrevocably consecrated) to YHWH — priestly property. The <em>cherem</em> category appears here as the ultimate form of divine ownership. Christ, in his resurrection, entered fully into divine possession — 'he was raised from the dead and will never die again; death no longer has dominion over him' (Rom 6:9). What is given entirely to YHWH and not redeemed becomes permanently his; Christ's resurrection body belongs permanently to the divine life.</p>",
    "22": "<p>An allusion: a purchased field (not ancestral) dedicated to YHWH gets its own valuation based on the Jubilee. The non-ancestral field dedicated by its purchaser — this is the situation of Gentiles brought into the covenant through Christ. The Gentiles are not the ancestral inheritance of the covenant people, but they have been 'purchased' (1 Cor 6:20; Rev 5:9) and dedicated to YHWH through Christ. Even the field that was not originally 'yours' can be dedicated to YHWH.</p>",
    "23": "<p>An allusion: the priest calculates the valuation up to the Jubilee year, and the dedicated person pays that sum as holy to YHWH. The precise accounting of the dedication system contrasts with the comprehensive sweep of Christ's redemption: 'He gave himself as a ransom for all' (1 Tim 2:6). No ledger-calculation is required in the new covenant; the debt was paid in full at the cross.</p>",
    "24": "<p>An allusion: at Jubilee, the field returns to its original owner. The Jubilee-return to original ownership points to the eschatological restoration: all of creation returning to its Creator's full possession. 'The creation itself will be set free from its bondage to corruption and obtain the freedom of the glory of the children of God' (Rom 8:21). The Jubilee's land-return is the natural type of the new creation's total restoration.</p>",
    "25": "<p>An allusion: 'Every valuation shall be according to the shekel of the sanctuary, twenty gerahs to the shekel.' The sanctuary shekel is the standard — the holy measure defines value. Christ as the standard by which all spiritual worth is measured: 'In him the whole fullness of deity dwells bodily' (Col 2:9). Every spiritual valuation that matters is calibrated to the one who is the fullness of God, the holy standard made flesh.</p>",
    "26": "<p>A direct type: 'But a firstborn of animals, which as a firstborn belongs to YHWH, no man may dedicate; whether ox or sheep, it is YHWH's.' The firstborn belongs to YHWH by right — it needs no special dedication because it is already his. Christ as 'the firstborn of all creation' (Col 1:15) and 'the firstborn from the dead' (Col 1:18; Rev 1:5): he belongs to YHWH as no creature does, not by dedication but by nature. The firstborn law of Leviticus points to the eternal Son who is the Father's own, the firstborn who precedes and exceeds every created firstborn.</p>",
    "27": "<p>An allusion: an unclean animal's firstborn may be redeemed at valuation plus a fifth, or sold. The unclean-firstborn redemption is what Christ accomplishes for humanity: 'You were bought with a price' (1 Cor 7:23). Humanity, the 'firstborn' of the image-bearing creatures (Gen 1:26-28), had become unclean through the fall. Christ redeems the unclean firstborn at the ultimate price — not a fifth surcharge but his own life.</p>",
    "28": "<p>An allusion: 'But no devoted thing (<em>cherem</em>) that a man devotes to YHWH, of anything that he has, whether man or beast or inherited field, shall be sold or redeemed; every devoted thing is most holy to YHWH.' The <em>cherem</em> — the irrevocably devoted — cannot be redeemed. This is the most absolute category in the dedication system. Yet Christ crosses even this boundary: what was given over to destruction (the condemned, the totally cursed) is what he came to redeem (Gal 3:13: 'redeemed us from the curse of the law'). No depth of devotion-to-destruction is beyond his reach.</p>",
    "29": "<p>An allusion: 'No one devoted (<em>cherem</em>) who is to be devoted from mankind shall be ransomed; he shall surely be put to death.' The <em>cherem</em> person receives the death penalty — no ransom is possible. Christ took this unredeemable category upon himself: 'Christ redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13). He entered the unredeemable category, bore the death it required, and in doing so ransomed those who were under condemnation from which no human ransom was possible.</p>",
    "30": "<p>An allusion: 'Every tithe of the land, whether of the seed of the land or of the fruit of the trees, is YHWH's; it is holy to YHWH.' The tithe principle — the tenth belongs to YHWH, signifying that all belongs to him. Christ as the true firstfruits and tithe: 'Christ has been raised from the dead, the firstfruits of those who have fallen asleep' (1 Cor 15:20). He is the first tenth given to YHWH, guaranteeing that the whole harvest follows.</p>",
    "31": "<p>An allusion: if a person redeems any of their tithe, they must add a fifth. The surcharge for reclaiming what was dedicated to YHWH — a pattern consistent throughout ch27. Giving to YHWH and then taking back costs more than simply giving. The principle of not drawing back from dedication to God: 'No one who puts his hand to the plow and looks back is fit for the kingdom of God' (Luke 9:62).</p>",
    "32": "<p>An allusion: 'And every tithe of herds and flocks, every tenth animal of all that pass under the herdsman's staff, shall be holy to YHWH.' The tithe of animals counted by the herdsman — every tenth. The Good Shepherd image: Christ is the shepherd who counts each sheep (Matt 18:12-13; Luke 15:4-7). In a striking reversal, the one who owns all the flocks does not demand the tenth — he gives himself for every last sheep, including the lost one that is not yet in the fold.</p>",
    "33": "<p>An allusion: 'One shall not differentiate between good and bad, neither shall he make a substitute for it; and if he does substitute for it, then both it and the substitute shall be holy; it shall not be redeemed.' The absolute non-substitutability of the tithe. Christ's death as the non-substitutable sacrifice: 'There is salvation in no one else, for there is no other name under heaven given among men by which we must be saved' (Acts 4:12). No substitution is possible in the economy of salvation — it is Christ or nothing.</p>",
    "34": "<p>A direct fulfillment: 'These are the commandments that YHWH commanded Moses for the people of Israel on Mount Sinai.' The closing verse of Leviticus — the entire book, with all its sacrifice regulations, purity laws, festival calendar, holiness code, blessings and curses, and dedication laws, is summarized in one sentence: received on Sinai, mediated by Moses, intended for Israel. Christ fulfills each element: he is the sacrifice (Heb 9-10), the purification (Heb 9:14), the festival's fulfillment (1 Cor 5:7; 15:23; Acts 2), the Holiness Code's embodiment ('be holy for I am holy,' 1 Pet 1:16), the one who bore the curse (Gal 3:13) and secured the blessing (Gal 3:14), and the one fully dedicated to YHWH (John 17:19). 'The law was given through Moses; grace and truth came through Jesus Christ' (John 1:17).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'leviticus')
    merge_comm(existing, LEVITICUS_CHRIST)
    save_comm('mkt-christ', 'leviticus', existing)
    for ch in ['26', '27']:
        vv = existing.get(ch, {})
        print(f'  ch{ch}: {len(vv)} verse(s) with christ commentary')

if __name__ == '__main__':
    main()
